// Command gen-make-reference extracts the make-target reference from the
// "## <target>: <description>" help comments in the repository Makefile and
// writes it as a Markdown table to docs/_generated/make-commands.md.
//
// The generated file is included by docs/dev-setup.md via a pymdownx.snippets
// --8<-- directive, so the documented command list stays in sync with the
// Makefile's own `make help` source of truth and cannot drift.
//
// Usage:
//
//	go run ./cmd/gen-make-reference              # rewrite the file in place
//	go run ./cmd/gen-make-reference -check       # exit non-zero if regen needed
//	go run ./cmd/gen-make-reference -output FILE # write to a different file
//	go run ./cmd/gen-make-reference -source FILE # read from a different Makefile
package main

import (
	"bufio"
	"bytes"
	"flag"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/sydlexius/stillwater/internal/filesystem"
)

// defaultSourcePath is the Makefile whose "## <target>: <description>" help
// comments are the source of truth (the same lines the `help` target prints).
const defaultSourcePath = "Makefile"

// defaultOutputPath is the generated Markdown file consumed by the --8<--
// snippet include in docs/dev-setup.md.
const defaultOutputPath = "docs/_generated/make-commands.md"

// fileHeader marks the output as generated so contributors do not hand-edit
// it. It is an HTML comment so it does not render as visible text.
const fileHeader = "<!-- Generated by gen-make-reference. DO NOT EDIT. Run 'make generate-docs' to regenerate. -->\n\n"

func main() {
	var (
		checkOnly  bool
		outPath    string
		sourcePath string
	)
	flag.BoolVar(&checkOnly, "check", false, "exit non-zero if the make-commands file needs to be regenerated")
	flag.StringVar(&outPath, "output", defaultOutputPath, "path to the generated Markdown file to write")
	flag.StringVar(&sourcePath, "source", defaultSourcePath, "path to the Makefile to read target help comments from")
	flag.Parse()

	if err := run(sourcePath, outPath, checkOnly); err != nil {
		fmt.Fprintln(os.Stderr, "gen-make-reference:", err)
		os.Exit(1)
	}
}

func run(sourcePath, outPath string, checkOnly bool) error {
	// sourcePath and outPath come from flags; this is a developer-only
	// build-time tool so configurable paths are intended.
	src, err := os.ReadFile(sourcePath) //nolint:gosec // G304: developer CLI, path is intentionally configurable
	if err != nil {
		return fmt.Errorf("read %s: %w", sourcePath, err)
	}

	targets, err := parseTargets(src)
	if err != nil {
		return fmt.Errorf("parse make targets from %s: %w", sourcePath, err)
	}

	rendered := renderTable(targets)

	// If the output file does not exist yet, treat its contents as empty so
	// the first run (check or write) behaves predictably.
	var existing []byte
	switch raw, rerr := os.ReadFile(outPath); { //nolint:gosec // G304: developer CLI, path is intentionally configurable
	case rerr == nil:
		existing = raw
	case os.IsNotExist(rerr):
		existing = nil
	default:
		return fmt.Errorf("read %s: %w", outPath, rerr)
	}

	updated := []byte(fileHeader + rendered)

	if checkOnly {
		if !bytes.Equal(existing, updated) {
			return fmt.Errorf("%s is stale; run `make generate-docs` to regenerate", filepath.ToSlash(outPath))
		}
		return nil
	}

	if bytes.Equal(existing, updated) {
		// Already up to date; skip the write so the file mtime is stable.
		return nil
	}

	// Ensure the output directory exists (docs/_generated/ may not exist in a
	// fresh checkout that has never run generate-docs).
	if err := os.MkdirAll(filepath.Dir(outPath), 0o750); err != nil {
		return fmt.Errorf("create output directory: %w", err)
	}

	if err := filesystem.WriteFileAtomic(outPath, updated, 0o644); err != nil {
		return fmt.Errorf("write %s: %w", outPath, err)
	}
	return nil
}

// makeTarget holds one parsed "## <name>: <description>" help entry.
type makeTarget struct {
	// Name is the make target, e.g. "build".
	Name string
	// Description is the prose after the first colon.
	Description string
}

// parseTargets extracts "## <name>: <description>" help comments from the
// Makefile, mirroring the convention consumed by the Makefile's own `help`
// target. Deeper-indented continuation lines ("##   Usage: ...") are skipped
// so multi-line usage hints do not produce spurious table rows.
//
// It fails if no help comments are found so a Makefile that drops the
// convention is caught at generation time rather than emitting an empty table.
func parseTargets(src []byte) ([]makeTarget, error) {
	var targets []makeTarget
	scanner := bufio.NewScanner(bytes.NewReader(src))
	for scanner.Scan() {
		line := scanner.Text()
		// Help comments are exactly "## <name>: <description>". Require the
		// "## " prefix and reject deeper-indented continuation lines whose
		// content starts with whitespace ("##   Usage: ...").
		if !strings.HasPrefix(line, "## ") {
			continue
		}
		rest := line[len("## "):]
		if rest == "" || rest[0] == ' ' || rest[0] == '\t' {
			continue
		}
		name, desc, ok := strings.Cut(rest, ":")
		if !ok {
			continue
		}
		name = strings.TrimSpace(name)
		desc = strings.TrimSpace(desc)
		if name == "" || desc == "" {
			continue
		}
		targets = append(targets, makeTarget{Name: name, Description: desc})
	}
	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("scan source: %w", err)
	}
	if len(targets) == 0 {
		return nil, fmt.Errorf("no `## <target>: <description>` help comments found in the Makefile")
	}
	return targets, nil
}

// renderTable converts parsed targets into a Markdown table whose rows match
// the order of the help comments in the Makefile (the same order `make help`
// prints).
func renderTable(targets []makeTarget) string {
	var b strings.Builder
	b.WriteString("| Command | Description |\n")
	b.WriteString("|---|---|\n")
	for _, t := range targets {
		fmt.Fprintf(&b, "| `make %s` | %s |\n", t.Name, escapePipes(t.Description))
	}
	return b.String()
}

// escapePipes escapes literal pipe characters in a description so they do not
// break the Markdown table layout.
func escapePipes(s string) string {
	return strings.ReplaceAll(s, "|", "\\|")
}
